### 2. Session Management: PermissionService / UserContext (module_52.cpp)

```cpp
// File: /app/project/src/module_52.cpp
// Lines: 51-69, 259-302

enum class Role {
    Reader,
    Author,
    Editor,
    Admin,
    SuperAdmin
};

struct UserContext final
{
    std::string            id;
    std::vector<Role>      roles;
    bool                   authenticated{false};

    bool hasRole(Role r) const noexcept
    {
        return std::find(roles.begin(), roles.end(), r) != roles.end();
    }
};

class PermissionService
{
public:
    bool hasPermission(const UserContext& user,
                       const ResourceDescriptor& resource,
                       std::string_view action)
    {
        // Check cache
        PermissionKey key{user.id, resource.ownerId, std::string(action)};
        if (auto cached = m_cache.get(key))
            return *cached;

        bool result = evaluate(user, resource, action);
        m_cache.put(key, result);
        return result;
    }
};
```

### 3. Password Reset Workflow (module_56.cpp)

```cpp
// File: /app/project/src/module_56.cpp
// Lines: 116-201

class PasswordResetService final
{
public:
    void requestPasswordReset(std::string_view email)
    {
        validateEmail(email);
        // Rate limiting check
        // Generate secure token
        const auto token = generateToken();
        // Persist token with expiry
        m_tokenRepo.upsertToken(token, {
            std::string{email},
            now + m_cfg.tokenLifetime
        });
        // Dispatch email asynchronously
        m_emailDispatcher.enqueueResetEmail(email, url.str());
    }

    void resetPassword(std::string_view token, std::string_view newPasswordHash)
    {
        auto record = m_tokenRepo.findToken(token);
        if (!record)
            throw TokenInvalid{"Password-reset token invalid."};
        if (now > record->expiresAt)
            throw TokenExpired{"Password-reset token expired."};

        m_userRepo.updatePassword(record->email, newPasswordHash);
        m_tokenRepo.removeToken(token);
    }
};
```

