   272→            // In production this would deserialize with protobuf/cap'n proto.
   273→            std::string serial(reinterpret_cast<char*>(blob.data()), blob.size());
   274→            std::istringstream iss(serial);
   275→
   276→            std::vector<Article> articles;
   277→            Article              art;
