   279→            {
   280→                std::getline(iss, art.title, '\n');
   281→                std::getline(iss, art.body, '\n');
   282→                art.isPublished = true;
   283→                articles.push_back(std::move(art));
   284→            }
   285→            m_index.build(articles);
