   296→
   297→    std::vector<Article> search(const std::string& rawQuery,
   298→                                std::size_t       limit = 10) const
   299→    {
   300→        if (rawQuery.empty()) return {};
   301→        std::vector<std::string> tokens;
   302→        tokenize(rawQuery, tokens);
   303→
   304→        auto scored = m_index.queryWithScore(tokens);
   305→        if (scored.empty()) return {};
   306→
   307→        // Convert to vector & sort by score desc
   308→        std::vector<std::pair<ArticleId, Score>> vec(scored.begin(), scored.end());
   309→        std::partial_sort(vec.begin(),
   310→                          vec.begin() + std::min(limit, vec.size()),
   311→                          vec.end(),
   312→                          [](auto& a, auto& b) { return a.second > b.second; });
   313→
   314→        std::vector<Article> result;
   315→        result.reserve(vec.size());
   316→
   317→        for (const auto& [aid, s] : vec)
   318→        {
   319→            auto maybeArt = m_articleRepo->findById(aid);
   320→            if (maybeArt) result.push_back(std::move(*maybeArt));
   321→            if (result.size() >= limit) break;
   322→        }
   323→        return result;
