   326→    // Force rebuild – exposed for maintenance endpoints
   327→    void rebuildIndex()
   328→    {
   329→        log("SearchService", "Rebuilding search index…");
   330→        auto articles = m_articleRepo->fetchAllPublished();
   331→        m_index.build(articles);
   332→
   333→        // Serialize minimal persistence data (again, demo only)
   334→        std::ostringstream oss;
   335→        for (const auto& a : articles)
