   367→                    {
   368→                        spdlog::warn(
   369→                            "[SearchService] Skipping article {}: {}", article.id,
   370→                            ex.what());
   371→                    }
   372→                    ++total;
   373→                }
   374→
   375→                offset += articles.size();
   376→
   377→                if (pause && *pause > std::chrono::milliseconds::zero())
   378→                    std::this_thread::sleep_for(*pause);
   379→            }
   380→            spdlog::info("[SearchService] Rebuild finished. {} articles processed.",
   381→                         total);
   382→        });
   383→    }
   384→
   385→private:
   386→    void processArticleChange(const domain::UUID &id)
   387→    {
   388→        auto optArticle = repo_->findById(id);
   389→        if (!optArticle)
   390→        {
   391→            spdlog::warn("[SearchService] article {} not found, deleting from index",
   392→                         id);
   393→            backend_->removeDocument(id);
   394→            return;
   395→        }
   396→
   397→        const auto &article = *optArticle;
   398→        try
   399→        {
   400→            if (article.isSearchable())
   401→            {
   402→                backend_->indexDocument(article);
   403→                spdlog::info("[SearchService] indexed article {}", id);
   404→            }
   405→            else
   406→            {
   407→                backend_->removeDocument(id);
   408→                spdlog::info("[SearchService] removed unpublished article {}", id);
   409→            }
   410→        }
   411→        catch (const std::exception &ex)
   412→        {
   413→            spdlog::error("[SearchService] failed to index article {}: {}", id,
   414→                          ex.what());
   415→        }
   416→    }
   417→
   418→    // Enable shared_from_this to keep the service alive until async jobs finish.
   419→    std::shared_ptr<FullTextSearchService> shared_from_this()
   420→    {
   421→        return std::shared_ptr<FullTextSearchService>(this, [](FullTextSearchService*){});
   422→    }
