    79→inline std::string base64url_encode(const std::vector<uint8_t>& data)
    80→{
    81→    BIO* b64 = BIO_new(BIO_f_base64());
    82→    BIO_set_flags(b64, BIO_FLAGS_BASE64_NO_NL);   // No newlines
    83→    BIO* bio = BIO_new(BIO_s_mem());
    84→    BIO_push(b64, bio);
    85→
    86→    BIO_write(b64, data.data(), static_cast<int>(data.size()));
    87→    BIO_flush(b64);
    88→
    89→    BUF_MEM* bufferPtr = nullptr;
    90→    BIO_get_mem_ptr(b64, &bufferPtr);
    91→
    92→    std::string encoded(bufferPtr->data, bufferPtr->length);
    93→    BIO_free_all(b64);
    94→
    95→    // Standard -> URL safe
    96→    for (char& c : encoded)
    97→    {
    98→        if (c == '+') c = '-';
    99→        else if (c == '/') c = '_';
   100→    }
   101→
   102→    // Trim padding '='
   103→    while (!encoded.empty() && encoded.back() == '=')
   104→        encoded.pop_back();
   105→
   106→    return encoded;
   107→}
