   146→class SecureTokenService
   147→{
   148→public:
   149→    struct Config
   150→    {
   151→        std::string       secretKey;     // HMAC secret (binary safe)
   152→        Seconds           defaultTTL     = Seconds { 900 }; // 15 minutes
   153→        std::string       issuer         = "IntraLedger-BlogSuite";
   154→        std::size_t       randomBytes    = 16;  // Random nonce length
   155→    };
   156→
   157→    explicit SecureTokenService(Config config)
   158→        : cfg_(std::move(config))
   159→    {
   160→        if (cfg_.secretKey.empty())
   161→            throw std::invalid_argument("Secret key must not be empty");
   162→    }
   163→
   164→    /*----------------------------------------------------
   165→     * generateToken
   166→     *
   167→     * Generates a compact, URL-safe token for an arbitrary
   168→     * user payload.  The payload is augmented with standard
   169→     * claims (iss, iat, exp, jti).
   170→     *---------------------------------------------------*/
   171→    std::string generateToken(Json userPayload,
   172→                              std::optional<Seconds> ttl = std::nullopt) const
   173→    {
   174→        const auto now = Clock::now();
   175→        const auto exp = now + (ttl ? *ttl : cfg_.defaultTTL);
   176→
   177→        userPayload["iss"] = cfg_.issuer;
   178→        userPayload["iat"] = std::chrono::duration_cast<Seconds>(
   179→                                 now.time_since_epoch()).count();
   180→        userPayload["exp"] = std::chrono::duration_cast<Seconds>(
   181→                                 exp.time_since_epoch()).count();
   182→        userPayload["jti"] = randomHex(cfg_.randomBytes);
   183→
   184→        const std::string payloadStr = userPayload.dump();
   185→        const std::vector<uint8_t> payloadBin(
   186→            payloadStr.begin(), payloadStr.end());
   187→
   188→        const std::string encodedPayload =
   189→            detail::base64url_encode(payloadBin);
   190→
   191→        const std::vector<uint8_t> signature =
   192→            hmacSHA256(encodedPayload);
   193→
   194→        const std::string encodedSig = detail::base64url_encode(signature);
   195→
   196→        return encodedPayload + '.' + encodedSig;
   197→    }
   198→
   199→    /*----------------------------------------------------
   200→     * verifyToken
   201→     *
   202→     * Checks integrity & validity, then returns the decoded
   203→     * payload on success.  On failure, a TokenError
   204→     * derivative is thrown.
   205→     *---------------------------------------------------*/
   206→    Json verifyToken(std::string_view token) const
   207→    {
   208→        const auto delimPos = token.find('.');
   209→        if (delimPos == std::string_view::npos)
   210→            throw TokenInvalid("Token format incorrect");
   211→
   212→        const std::string_view encodedPayload = token.substr(0, delimPos);
   213→        const std::string_view encodedSig     =
   214→            token.substr(delimPos + 1);
   215→
   216→        // Verify signature
   217→        const std::vector<uint8_t> expectedSig =
   218→            hmacSHA256(encodedPayload);
   219→
   220→        const std::vector<uint8_t> providedSig =
   221→            detail::base64url_decode(encodedSig);
   222→
   223→        if (!constantTimeEquals(expectedSig, providedSig))
   224→            throw TokenInvalid("Signature mismatch");
   225→
   226→        // Decode payload
   227→        const std::vector<uint8_t> payloadBin =
   228→            detail::base64url_decode(encodedPayload);
   229→        const std::string payloadStr(payloadBin.begin(), payloadBin.end());
   230→
   231→        Json payload;
   232→        try
   233→        {
   234→            payload = Json::parse(payloadStr);
   235→        }
   236→        catch (const Json::exception& e)
   237→        {
   238→            throw TokenInvalid("Malformed JSON payload");
   239→        }
   240→
   241→        // Validate timestamps
   242→        const auto nowSecs =
   243→            std::chrono::duration_cast<Seconds>(
   244→                Clock::now().time_since_epoch()).count();
   245→
   246→        if (payload.contains("exp") && payload["exp"].is_number())
   247→        {
   248→            if (nowSecs > payload["exp"].get<int64_t>())
   249→                throw TokenExpired();
   250→        }
   251→
   252→        if (payload.contains("nbf") && payload["nbf"].is_number())
   253→        {
   254→            if (nowSecs < payload["nbf"].get<int64_t>())
   255→                throw TokenInvalid("Token not yet valid (nbf)");
   256→        }
   257→
   258→        return payload;
   259→    }
   260→
   261→private:
   262→    Config cfg_;
   263→
   264→    /*----------------------------------------------------
   265→     * hmacSHA256
   266→     *---------------------------------------------------*/
   267→    std::vector<uint8_t> hmacSHA256(std::string_view data) const
   268→    {
   269→        unsigned int len = EVP_MAX_MD_SIZE;
   270→        std::vector<uint8_t> result(len);
   271→
   272→        HMAC_CTX* ctx = HMAC_CTX_new();
   273→        if (!ctx)
   274→            throw TokenError("HMAC_CTX allocation failed");
   275→
   276→        if (HMAC_Init_ex(ctx,
   277→                         cfg_.secretKey.data(),
   278→                         static_cast<int>(cfg_.secretKey.size()),
   279→                         EVP_sha256(), nullptr) != 1)
   280→        {
   281→            HMAC_CTX_free(ctx);
   282→            throw TokenError("HMAC_Init_ex failed");
   283→        }
   284→
   285→        HMAC_Update(ctx,
   286→                    reinterpret_cast<const unsigned char*>(data.data()),
   287→                    data.size());
   288→
   289→        HMAC_Final(ctx, result.data(), &len);
   290→        HMAC_CTX_free(ctx);
   291→        result.resize(len);
   292→        return result;
   293→    }
