   295→    /*----------------------------------------------------
   296→     * randomHex
   297→     *
   298→     * Generates a cryptographically secure random hex
   299→     * string of length `byteCount * 2`.
   300→     *---------------------------------------------------*/
   301→    static std::string randomHex(std::size_t byteCount)
   302→    {
   303→        std::vector<uint8_t> buf(byteCount);
   304→        if (RAND_bytes(buf.data(), static_cast<int>(buf.size())) != 1)
   305→            throw TokenError("RAND_bytes failed");
   306→
   307→        std::ostringstream oss;
   308→        oss << std::hex << std::setfill('0');
   309→        for (uint8_t b : buf)
   310→            oss << std::setw(2) << static_cast<int>(b);
   311→        return oss.str();
   312→    }
   313→
   314→    /*----------------------------------------------------
   315→     * constantTimeEquals
   316→     *
   317→     * Compares two byte sequences in constant time to
   318→     * mitigate timing attacks.
   319→     *---------------------------------------------------*/
   320→    static bool constantTimeEquals(std::span<const uint8_t> a,
   321→                                   std::span<const uint8_t> b)
   322→    {
   323→        if (a.size() != b.size())
   324→            return false;
   325→        uint8_t diff = 0;
   326→        for (std::size_t i = 0; i < a.size(); ++i)
   327→            diff |= a[i] ^ b[i];
   328→        return diff == 0;
   329→    }
