   318→    {
   319→        repository::PostRepository postRepo{m_session};
   320→
   321→        // ------------------------------------------------------------------
   322→        // 1. Retrieve + Validate
   323→        // ------------------------------------------------------------------
   324→        auto postOpt = postRepo.findById(postId);
   325→        if (!postOpt.has_value())
   326→            throw PostNotFoundError(fmt::format("Post id={} not found", postId));
   327→
   328→        domain::Post& post = *postOpt;
   329→        if (post.status == domain::PostStatus::Published)
   330→            throw PublishConflictError{fmt::format("Post id={} already published", postId)};
   331→
   332→        // ------------------------------------------------------------------
   333→        // 2. Persist inside a DB transaction
   334→        // ------------------------------------------------------------------
   335→        m_session->withTransaction([&](core::orm::Session& /*txSession*/) {
   336→            using namespace std::chrono;
   337→            post.status      = domain::PostStatus::Published;
   338→            post.publishedAt = system_clock::now();
