    73→class LoginAttemptThrottler {
    74→public:
    75→    struct Limits {
    76→        std::uint32_t maxAttempts;                         // Number of attempts before lockout
    77→        std::chrono::seconds window;                       // Rolling window duration
    78→        std::chrono::seconds lockout;                      // How long the user is locked
