   100→private:
   101→    struct CounterState {
   102→        std::uint32_t counter{0};
   103→        std::chrono::system_clock::time_point windowStart{};
   104→        std::chrono::system_clock::time_point lockedUntil{};
   105→        bool dirty{false};     // Whether state changed (needs persistence)
   106→    };
