   183→void LoginAttemptThrottler::touch(const std::string& key, Limits limits)
   184→{
   185→    using namespace std::chrono;
   186→    const auto now = system_clock::now();
   187→
   188→    std::lock_guard lk{mtx_};
   189→    auto& state = cache_[key];  // Creates if missing
   190→
   191→    // Reset window if expired
   192→    if (now - state.windowStart > limits.window) {
   193→        state.counter = 0;
   194→        state.windowStart = now;
   195→    }
   196→
   197→    // Increment and determine lockout
   198→    ++state.counter;
   199→    if (state.counter >= limits.maxAttempts) {
   200→        state.lockedUntil = now + limits.lockout;
   201→        // Reset counter so that after lockout new window starts clean
   202→        state.counter = 0;
   203→        state.windowStart = state.lockedUntil;  // Next window begins after lockout expires
   204→    }
   205→
   206→    state.dirty = true;
   207→}
