   233→void LoginAttemptThrottler::persistOne(const std::string& key,
   234→                                       const CounterState& state,
   235→                                       orm::EntityManager& em)
   236→{
   237→    if (!state.dirty) { return; }
   238→
   239→    LoginAttemptDTO dto;
   240→    dto.key = key;
   241→    dto.counter = state.counter;
   242→    dto.windowStart = state.windowStart;
   243→    dto.lockedUntil = state.lockedUntil;
   244→
   245→    em.persistOrUpdate(dto);
