   248→void LoginAttemptThrottler::flushToDatabase()
   249→{
   250→    std::unordered_map<std::string, CounterState> snapshot;
   251→    {
   252→        std::lock_guard lk{mtx_};
   253→        snapshot = cache_;  // Cheap with move (C++17 guaranteed)
   254→        for (auto& [_, state] : cache_) { state.dirty = false; }
   255→    }
   256→
   257→    orm::Transaction txn{em_};
   258→    util::ScopeGuard guard{[&]() noexcept {
   259→        txn.rollback();
   260→    }};
   261→
   262→    try {
   263→        for (const auto& [key, state] : snapshot) {
   264→            persistOne(key, state, em_);
   265→        }
   266→        txn.commit();
   267→        guard.dismiss();
   268→    } catch (const std::exception& ex) {
   269→        util::Logger::error("LoginAttemptThrottler.flushToDatabase: {}", ex.what());
   270→    }
   271→}
