   109→// Dumb, single-threaded in-memory search backend (tf-idf-ish scoring).
   110→class InMemorySearchBackend final : public ISearchBackend
   111→{
   112→public:
   113→    void put(const Document& doc) override
   114→    {
   115→        std::unique_lock lock(_mtx);
   116→        _docs[doc.id] = doc;
   117→        index(doc);
   118→    }
   119→
   120→    void remove(const std::string& id) override
   121→    {
   122→        std::unique_lock lock(_mtx);
   123→        _docs.erase(id);
   124→        for (auto& [tok, posting] : _inverted) { posting.erase(id); }
   125→    }
   126→
   127→    std::vector<std::pair<std::string, double>> query(const std::vector<std::string>& terms,
   128→                                                      int limit,
   129→                                                      int offset) const override
   130→    {
   131→        std::shared_lock lock(_mtx);
   132→        std::unordered_map<std::string, double> scores;
   133→
   134→        for (const auto& term : terms)
   135→        {
   136→            auto it = _inverted.find(term);
   137→            if (it == _inverted.end()) continue;
   138→
   139→            const auto& posting = it->second;
   140→            for (auto&& [docId, count] : posting)
   141→            {
   142→                double tf   = static_cast<double>(count);
   143→                double idf  = 1.0 + std::log(static_cast<double>(_docs.size()) /
   144→                                            (1.0 + posting.size()));
   145→                scores[docId] += tf * idf;
   146→            }
   147→        }
   148→
   149→        std::vector<std::pair<std::string, double>> sorted(scores.begin(), scores.end());
   150→        std::sort(sorted.begin(),
   151→                  sorted.end(),
   152→                  [](auto& a, auto& b) { return a.second > b.second; });
   153→
   154→        if (offset >= static_cast<int>(sorted.size())) return {};
   155→        auto beg = sorted.begin() + offset;
   156→        auto end = (limit > 0)
   157→                       ? beg + std::min(limit, static_cast<int>(sorted.end() - beg))
   158→                       : sorted.end();
   159→        return {beg, end};
   160→    }
   161→
   162→private:
   163→    static std::string canonicalise(std::string_view s)
   164→    {
   165→        std::string out;
   166→        out.reserve(s.size());
   167→        for (char c : s)
   168→        {
   169→            if (std::isalnum(static_cast<unsigned char>(c)))
   170→                out.push_back(static_cast<char>(std::tolower(c)));
   171→            else
   172→                out.push_back(' ');
   173→        }
   174→        return out;
   175→    }
   176→
   177→    static std::vector<std::string> tokenize(std::string_view text)
   178→    {
   179→        std::vector<std::string> tokens;
   180→        std::istringstream       ss(std::string(text));
   181→        std::string              tok;
   182→        while (ss >> tok) tokens.emplace_back(tok);
   183→        return tokens;
   184→    }
   185→
   186→    void index(const Document& doc)
   187→    {
   188→        const std::string canon = canonicalise(doc.title + " " + doc.body);
   189→        for (const auto& tok : tokenize(canon))
   190→        {
   191→            _inverted[tok][doc.id] += 1u;
   192→        }
   193→    }
