   275→public:
   276→    struct Parsed
   277→    {
   278→        std::vector<std::string> tokens;     // canonical tokens
   279→        std::vector<std::string> phrases;    // exact phrases (w/o quotes)
   280→    };
   281→
   282→    Parsed parse(std::string_view raw) const
   283→    {
   284→        Parsed                       result;
   285→        static const std::regex      phraseRe("\"([^\"]+)\"");
   286→        std::smatch                  m;
   287→        std::string                  s(raw);
   288→
   289→        // Extract phrases
   290→        auto searchStart = s.cbegin();
   291→        while (std::regex_search(searchStart, s.cend(), m, phraseRe))
   292→        {
   293→            result.phrases.emplace_back(m[1]);
   294→            searchStart = m.suffix().first;
   295→        }
   296→
   297→        // Remove quotes for tokenisation
   298→        std::string withoutQuotes = std::regex_replace(s, phraseRe, " ");
   299→        for (auto& tok : tokenize(canonicalise(withoutQuotes)))
   300→            if (_stopWords.find(tok) == _stopWords.end())
   301→                result.tokens.emplace_back(std::move(tok));
   302→
   303→        return result;
   304→    }
   305→
   306→    static std::string
   307→    highlight(std::string_view text,
   308→              const std::vector<std::string>& terms,
   309→              std::string_view                 preTag  = "<mark>",
   310→              std::string_view                 postTag = "</mark>")
   311→    {
   312→        std::string out(text);
   313→        for (const auto& term : terms)
   314→        {
   315→            std::regex re("\\b(" + term + ")\\b", std::regex::icase);
   316→            out = std::regex_replace(out, re, std::string(preTag) + "$1" + std::string(postTag));
   317→        }
   318→        return out;
   319→    }
