   314→// -----------------------------------------------------------------------------
   315→// Query Evaluator
   316→// -----------------------------------------------------------------------------
   317→
   318→class QueryEvaluator {
   319→public:
   320→    explicit QueryEvaluator(const QueryNode* root) : root_(root) {}
   321→
   322→    DocumentList filter(const DocumentList& corpus) {
   323→        DocumentList out;
   324→        for (const auto& doc : corpus) {
   325→            if (match_node(root_, doc)) { out.push_back(doc); }
   326→        }
   327→        return out;
   328→    }
   329→
   330→private:
   331→    const QueryNode* root_;
   332→
   333→    static bool match_term(const Document& doc, const std::string& term) {
   334→        auto haystack = util::to_lower(doc.title + " " + doc.content);
   335→        auto needle   = util::to_lower(term);
   336→        return haystack.find(needle) != std::string::npos;
   337→    }
   338→
   339→    static bool match_phrase(const Document& doc, const std::string& phrase) {
   340→        auto haystack = util::to_lower(doc.title + " " + doc.content);
   341→        auto needle   = util::to_lower(phrase);
   342→        return haystack.find(needle) != std::string::npos;
   343→    }
   344→
   345→    bool match_node(const QueryNode* node, const Document& doc) {
   346→        switch (node->type) {
   347→            case NodeType::TERM:
   348→                return match_term(doc, node->term);
   349→            case NodeType::PHRASE:
   350→                return match_phrase(doc, node->term);
   351→            case NodeType::AND:
   352→                return std::all_of(
   353→                    node->children.begin(), node->children.end(),
   354→                    [&](const std::unique_ptr<QueryNode>& ch) { return match_node(ch.get(), doc); });
   355→            case NodeType::OR:
   356→                return std::any_of(
   357→                    node->children.begin(), node->children.end(),
   358→                    [&](const std::unique_ptr<QueryNode>& ch) { return match_node(ch.get(), doc); });
   359→            case NodeType::NOT:
   360→                return !match_node(node->children.front().get(), doc);
   361→            default:
   362→                return false;
   363→        }
   364→    }
   365→};
