   367→// -----------------------------------------------------------------------------
   368→// Search Service
   369→// -----------------------------------------------------------------------------
   370→
   371→class SearchService {
   372→public:
   373→    explicit SearchService(std::shared_ptr<DocumentRepository> repo,
   374→                           std::size_t                         cache_entries = 512)
   375→        : repo_(std::move(repo)), cache_(cache_entries) {}
   376→
   377→    // Asynchronous interface: returns future<SearchResponse>
   378→    std::future<SearchResponse> search_async(SearchRequest req) {
   379→        return std::async(std::launch::async, [this, req = std::move(req)]() {
   380→            return this->search(req);
   381→        });
   382→    }
   383→
   384→private:
   385→    SearchResponse search(const SearchRequest& req) {
   386→        const auto start_time = std::chrono::steady_clock::now();
   387→
   388→        // Attempt cache lookup
   389→        SearchResponse cached;
   390→        if (cache_.get(req.query, cached)) {
   391→            // apply offset/limit at response time to avoid storing slices
   392→            SearchResponse resp = cached;
   393→            resp.hits = slice(resp.hits, req.offset, req.limit);
   394→            resp.took = std::chrono::duration_cast<std::chrono::milliseconds>(
   395→                std::chrono::steady_clock::now() - start_time);
   396→            return resp;
   397→        }
   398→
   399→        // Parse
   400→        auto parser = QueryParser(req.query);
   401→        auto ast    = parser.parse();
   402→
   403→        // Evaluate
   404→        auto corpus = repo_->fetch_all();
   405→        if (!req.locale.empty()) {
   406→            corpus.erase(std::remove_if(corpus.begin(), corpus.end(),
   407→                                        [&](const Document& d) {
   408→                                            return d.locale != req.locale;
   409→                                        }),
   410→                         corpus.end());
   411→        }
   412→
   413→        QueryEvaluator evaluator(ast.get());
   414→        auto           matches = evaluator.filter(corpus);
   415→
   416→        // Sort by publish date desc
   417→        std::sort(matches.begin(), matches.end(), [](const auto& a, const auto& b) {
   418→            return a.published_at > b.published_at;
   419→        });
   420→
   421→        SearchResponse resp;
   422→        resp.total_hits = matches.size();
   423→        resp.hits       = slice(matches, req.offset, req.limit);
   424→        resp.took       = std::chrono::duration_cast<std::chrono::milliseconds>(
   425→            std::chrono::steady_clock::now() - start_time);
   426→
   427→        // Put in cache (store full hits, not sliced)
   428→        cache_.put(req.query,
   429→                   SearchResponse{matches, resp.total_hits,
   430→                                  resp.took});  // storing took is fine; will be recomputed
   431→
   432→        return resp;
   433→    }
   434→
   435→    static DocumentList slice(const DocumentList& v, std::size_t offset, std::size_t limit) {
   436→        if (offset >= v.size()) return {};
   437→        auto first = v.begin() + static_cast<std::ptrdiff_t>(offset);
   438→        auto last  = (limit == 0 || offset + limit > v.size())
   439→                         ? v.end()
   440→                         : first + static_cast<std::ptrdiff_t>(limit);
   441→        return {first, last};
   442→    }
   443→
   444→    std::shared_ptr<DocumentRepository> repo_;
   445→    LruCache<std::string, SearchResponse> cache_;
   446→};
