   203→//------------------------------------------------------------------------------
   204→// Recursive-descent parser for simple boolean query grammar
   205→// Supports:
   206→//      term           -> WORD | "PHRASE"
   207→//      factor         -> [NOT] term
   208→//      expr_and       -> factor { AND factor }
   209→//      expr_or        -> expr_and { OR expr_and }
   210→//      query          -> expr_or
   211→//--------------------------------------------------------------------------
   212→
   213→class QueryParser
   214→{
   215→public:
   216→    explicit QueryParser(std::string_view q)
   217→        : m_query(q)
   218→    {
   219→        util::ascii_to_lower(m_query); // case-folding
   220→    }
   221→
   222→    NodePtr parse()
   223→    {
   224→        m_pos = 0;
   225→        NodePtr root = parse_or();
   226→        consume_whitespace();
   227→        if (m_pos != m_query.size())
   228→            throw std::runtime_error("Unexpected trailing characters");
   229→        return root;
   230→    }
   231→
   232→private:
   233→    std::string m_query;
   234→    std::size_t m_pos { 0 };
   235→
   236→    [[nodiscard]] bool eof() const noexcept { return m_pos >= m_query.size(); }
   237→
   238→    void consume_whitespace()
   239→    {
   240→        while (!eof() && std::isspace(static_cast<unsigned char>(m_query[m_pos])))
   241→            ++m_pos;
   242→    }
   243→
   244→    bool match_keyword(std::string_view kw)
   245→    {
   246→        consume_whitespace();
   247→        if (m_query.compare(m_pos, kw.size(), kw) == 0)
   248→        {
   249→            const auto next = m_pos + kw.size();
   250→            if (next == m_query.size() || std::isspace(static_cast<unsigned char>(m_query[next])))
   251→            {
   252→                m_pos = next;
   253→                return true;
   254→            }
   255→        }
   256→        return false;
   257→    }
   258→
   259→    NodePtr parse_or()
   260→    {
   261→        std::vector<NodePtr> nodes;
   262→        nodes.push_back(parse_and());
   263→        while (match_keyword("or"))
   264→            nodes.push_back(parse_and());
   265→
   266→        if (nodes.size() == 1)
   267→            return nodes.front();
   268→        return std::make_shared<BoolNode>(BoolOperator::Or, std::move(nodes));
   269→    }
   270→
   271→    NodePtr parse_and()
   272→    {
   273→        std::vector<NodePtr> nodes;
   274→        nodes.push_back(parse_factor());
   275→        while (match_keyword("and"))
   276→            nodes.push_back(parse_factor());
   277→
   278→        if (nodes.size() == 1)
   279→            return nodes.front();
   280→        return std::make_shared<BoolNode>(BoolOperator::And, std::move(nodes));
   281→    }
   282→
   283→    NodePtr parse_factor()
   284→    {
   285→        consume_whitespace();
   286→        bool neg = false;
   287→        if (match_keyword("not"))
   288→            neg = true;
   289→
   290→        return parse_term(neg);
   291→    }
   292→
   293→    NodePtr parse_term(bool negated)
   294→    {
   295→        consume_whitespace();
   296→        if (eof())
   297→            throw std::runtime_error("Unexpected end of query");
   298→
   299→        char ch = m_query[m_pos];
   300→        if (ch == '"')
   301→        {
   302→            ++m_pos;
   303→            std::size_t end = m_query.find('"', m_pos);
   304→            if (end == std::string::npos)
   305→                throw std::runtime_error("Unterminated quote");
   306→
   307→            std::string phrase = m_query.substr(m_pos, end - m_pos);
   308→            m_pos = end + 1;
   309→            return std::make_shared<TermNode>(std::move(phrase), negated);
   310→        }
   311→
   312→        // Word
   313→        std::size_t start = m_pos;
   314→        while (!eof() && !std::isspace(static_cast<unsigned char>(m_query[m_pos])))
   315→            ++m_pos;
   316→
   317→        std::string word = m_query.substr(start, m_pos - start);
   318→        return std::make_shared<TermNode>(std::move(word), negated);
   319→    }
   320→};
