   304→
   305→class Parser
   306→{
   307→public:
   308→    explicit Parser(std::string_view input) : m_lexer(input)
   309→    {
   310→        m_lexer.reset(); // initialise first token
   311→    }
   312→
   313→    NodePtr parse()
   314→    {
   315→        auto expr = parse_or();
   316→        expect(TokenType::EndOfInput);
   317→        return expr;
   318→    }
   319→
   320→private:
   321→    Lexer m_lexer;
   322→
   323→    // Highest level: OR
   324→    NodePtr parse_or()
   325→    {
   326→        auto node = parse_and();
   327→        while (match(TokenType::Or))
   328→        {
   329→            auto rhs = parse_and();
   330→            node     = std::make_unique<QueryNode>(Or { std::move(node), std::move(rhs) });
   331→        }
   332→        return node;
   333→    }
   334→
   335→    // Intermediate level: AND (implicit or explicit)
   336→    NodePtr parse_and()
   337→    {
   338→        auto node = parse_unary();
   339→
   340→        while (true)
   341→        {
   342→            if (match(TokenType::And))
   343→            {
   344→                auto rhs = parse_unary();
   345→                node     = std::make_unique<QueryNode>(And { std::move(node), std::move(rhs) });
   346→            }
   347→            // Implicit AND: two consecutive terms / groups
   348→            else if (peek_any({ TokenType::Word, TokenType::Phrase, TokenType::LParen, TokenType::Not }))
   349→            {
   350→                auto rhs = parse_unary();
   351→                node     = std::make_unique<QueryNode>(And { std::move(node), std::move(rhs) });
   352→            }
   353→            else
   354→            {
   355→                break;
   356→            }
   357→        }
   358→
   359→        return node;
   360→    }
   361→
   362→    // Unary: NOT
   363→    NodePtr parse_unary()
   364→    {
   365→        if (match(TokenType::Not))
   366→        {
   367→            auto arg = parse_unary();
   368→            return std::make_unique<QueryNode>(Not { std::move(arg) });
   369→        }
   370→        return parse_primary();
   371→    }
   372→
   373→    // Primary: term, phrase, parenthesis, field filter
   374→    NodePtr parse_primary()
   375→    {
   376→        if (match(TokenType::LParen))
   377→        {
   378→            auto inner = parse_or();
   379→            expect(TokenType::RParen);
   380→            return inner;
   381→        }
   382→
   383→        if (peek(TokenType::Word))
   384→        {
   385→            auto wordTok = m_lexer.next();
   386→
   387→            // Field filter?
   388→            if (match(TokenType::Colon))
   389→            {
   390→                const std::string fieldName = to_lower(wordTok.lexeme);
   391→
   392→                // Support only whitelisted fields
   393→                if (!is_whitelisted_field(fieldName))
   394→                    throw ParseError { "Unknown filter field '" + fieldName + "'", wordTok.position };
   395→
   396→                // Value can be phrase or term
   397→                NodePtr valueNode;
   398→                if (peek(TokenType::Phrase))
   399→                {
   400→                    auto phraseTok = m_lexer.next();
   401→                    valueNode      = std::make_unique<QueryNode>(Phrase { phraseTok.lexeme });
   402→                }
   403→                else if (peek(TokenType::Word))
   404→                {
   405→                    auto termTok = m_lexer.next();
   406→                    valueNode    = std::make_unique<QueryNode>(Term { termTok.lexeme });
   407→                }
   408→                else
   409→                {
   410→                    throw ParseError { "Missing value after field filter ':'", m_lexer.peek().position };
   411→                }
   412→
   413→                return std::make_unique<QueryNode>(FieldFilter { fieldName, std::move(valueNode) });
   414→            }
   415→
   416→            /* Plain term */
   417→            return std::make_unique<QueryNode>(Term { wordTok.lexeme });
   418→        }
   419→
   420→        if (peek(TokenType::Phrase))
   421→        {
   422→            auto phraseTok = m_lexer.next();
   423→            return std::make_unique<QueryNode>(Phrase { phraseTok.lexeme });
   424→        }
   425→
   426→        throw ParseError { "Unexpected token '" + m_lexer.peek().lexeme + "'", m_lexer.peek().position };
   427→    }
   428→
   429→    // Helper ────────────────────────────────────────────────────────────────
   430→
   431→    bool match(TokenType t)
   432→    {
   433→        if (peek(t))
   434→        {
   435→            m_lexer.consume();
   436→            return true;
   437→        }
   438→        return false;
   439→    }
   440→
   441→    void expect(TokenType t)
   442→    {
   443→        if (!match(t))
   444→            throw ParseError { "Expected different token", m_lexer.peek().position };
   445→    }
   446→
   447→    bool peek(TokenType t) const { return m_lexer.peek().type == t; }
   448→
   449→    bool peek_any(std::initializer_list<TokenType> list) const
   450→    {
   451→        const TokenType cur = m_lexer.peek().type;
   452→        return std::find(list.begin(), list.end(), cur) != list.end();
   453→    }
   454→
   455→    static std::string to_lower(std::string_view sv)
   456→    {
   457→        std::string out;
   458→        out.reserve(sv.size());
   459→        std::transform(sv.begin(), sv.end(), std::back_inserter(out),
   460→                       [](unsigned char c) { return static_cast<char>(std::tolower(c)); });
   461→        return out;
   462→    }
   463→
   464→    static bool is_whitelisted_field(const std::string& field)
   465→    {
   466→        static constexpr std::array allowed = { "title", "body", "tag", "author" };
   467→        return std::find(allowed.begin(), allowed.end(), field) != allowed.end();
   468→    }
   469→};
