   474→
   475→struct SqlFragment
   476→{
   477→    std::string              sql;     // WHERE clause without the "WHERE" keyword
   478→    std::vector<std::string> params;  // positional parameters to bind in order
   479→};
   480→
   481→class SqlTranslator
   482→{
   483→public:
   484→    // Compile AST into SQL WHERE fragment
   485→    SqlFragment compile(const QueryNode& root)
   486→    {
   487→        m_buffer.clear();
   488→        m_params.clear();
   489→        walk(root);
   490→        return { m_buffer.str(), m_params };
   491→    }
   492→
   493→private:
   494→    std::ostringstream        m_buffer;
   495→    std::vector<std::string>  m_params;
   496→
   497→    // Depth-first traversal
   498→    void walk(const QueryNode& node)
   499→    {
   500→        std::visit([this](auto&& n) { generate(n); }, node);
   501→    }
   502→
   503→    // Generates SQL with PostgreSQL/MariaDB full-text search in mind.
   504→    // The ORM will later splice this fragment into a larger statement.
   505→    void generate(const Term& n)
   506→    {
   507→        emit_param(to_tsquery(n.value));
   508→    }
   509→
   510→    void generate(const Phrase& n)
   511→    {
   512→        emit_param(to_tsquery_phrase(n.value));
   513→    }
   514→
   515→    void generate(const FieldFilter& n)
   516→    {
   517→        m_buffer << '(';
   518→        const std::string columnName = map_field_to_column(n.field);
   519→        m_buffer << columnName << " @@ ";
   520→        walk(*n.arg);
   521→        m_buffer << ')';
   522→    }
   523→
   524→    void generate(const Not& n)
   525→    {
   526→        m_buffer << "NOT (";
   527→        walk(*n.arg);
   528→        m_buffer << ')';
   529→    }
   530→
   531→    void generate(const And& n)
   532→    {
   533→        m_buffer << '(';
   534→        walk(*n.lhs);
   535→        m_buffer << " AND ";
   536→        walk(*n.rhs);
   537→        m_buffer << ')';
