   121→            auto& bucket = m_buckets.try_emplace(key, m_cfg.capacity, now).first->second;
   122→
   123→            refill(bucket, now);
   124→
   125→            if (tokens > bucket.tokensAvailable) {
   126→                return std::nullopt;
   127→            }
   128→
   129→            bucket.tokensAvailable -= tokens;
   130→            return bucket.tokensAvailable;
   131→        }
   132→    }
   133→
   134→    std::optional<std::chrono::milliseconds> retryAfter(const std::string& key) override
   135→    {
   136→        using clock = std::chrono::steady_clock;
   137→        const auto now = clock::now();
   138→
   139→        std::scoped_lock lock{m_mutex};
