   141→        const auto it = m_buckets.find(key);
   142→        if (it == m_buckets.end())
   143→            return std::nullopt;
   144→
   145→        const detail::Bucket& bucket = it->second;
   146→        if (bucket.tokensAvailable > 0)
   147→            return std::chrono::milliseconds{0};
