   153→            waitMs = std::chrono::milliseconds{0};
   154→        return waitMs;
   155→    }
   156→
   157→private:
   158→    void refill(detail::Bucket& bucket,
   159→                std::chrono::steady_clock::time_point now)
   160→    {
   161→        const auto elapsed = now - bucket.lastRefill;
   162→        if (elapsed < m_cfg.refillInterval)
   163→            return;
   164→
   165→        const uint64_t intervals = static_cast<uint64_t>(
   166→            elapsed / m_cfg.refillInterval);
   167→        const uint64_t newTokens = intervals * m_cfg.refillAmount;
   168→
   169→        bucket.tokensAvailable = std::min<uint64_t>(
   170→            bucket.tokensAvailable + newTokens, m_cfg.capacity);
   171→        bucket.lastRefill = bucket.lastRefill + intervals * m_cfg.refillInterval;
   172→    }
   173→
   174→private:
   175→    Config                                                              m_cfg;
   176→    std::unordered_map<std::string, detail::Bucket>                     m_buckets;
   177→    std::mutex                                                          m_mutex;
   178→};
