   102→class ContentMetricsService {
   103→public:
   104→    ContentMetricsService(std::shared_ptr<IArticleRepository> repo,
   105→                          std::shared_ptr<ICacheProvider>     cache,
   106→                          std::shared_ptr<IJobDispatcher>     dispatcher,
   107→                          std::chrono::seconds                dedupWindow =
