   144→        // Persist asynchronously when threshold is reached.
   145→        // A threshold of 25 minimizes DB chatter while keeping counters fresh.
   146→        constexpr std::size_t flushThreshold = 25;
   147→        commitIfNeeded(articleId, flushThreshold);
