   149→        // Memoize dedup key.
   150→        cache_->set(dedupKey, "1", dedupWindow_);
   151→    }
   152→
   153→    // Flush all in-memory buckets to the persistent store. Exposed for graceful
   154→    // shutdown or periodic cron invocation.
   155→    void flushAll()
   156→    {
   157→        std::unordered_map<std::uint64_t, std::uint64_t> snapshot;
   158→        {
   159→            std::unique_lock lk(bucketsMutex_);
   160→            snapshot.swap(viewBuckets_);
   161→        }
   162→
   163→        for (const auto& [articleId, increment] : snapshot) {
   164→            applyIncrement(articleId, increment);
