   167→
   168→    // Compute the N most trending articles within the given look-back window.
   169→    // Complexity: O(M log N) where M is #articles published since cutoff.
   170→    std::vector<ArticleMetrics>
   171→    trending(std::size_t topN,
   172→             std::chrono::hours windowSize = std::chrono::hours{ 24 })
   173→    {
   174→        using namespace std::chrono;
