    51→// Basic ASCII-only lower-case conversion; replace with full UTF-8 case folding
    52→// via ICU or boost::locale in production builds that need it.
    53→inline std::string ascii_to_lower(std::string_view sv) {
    54→    std::string out;
    55→    out.reserve(sv.size());
    56→    for (unsigned char ch : sv) {
    57→        out.push_back(static_cast<char>(std::tolower(ch)));
    58→    }
    59→    return out;
    60→}
    61→
    62→// Trim whitespace (both ends, ASCII definition)
    63→inline std::string_view trim_ascii(std::string_view sv) {
    64→    auto begin = sv.find_first_not_of(" \t\r\n");
    65→    if (begin == std::string_view::npos) return {};
    66→    auto end = sv.find_last_not_of(" \t\r\n");
    67→    return sv.substr(begin, end - begin + 1);
    68→}
