    70→// -----------------------------------------------------------------------------
    71→// Thread-safe, capacity-bounded LRU cache
    72→// -----------------------------------------------------------------------------
    73→
    74→template <typename Key, typename Value, typename Hash = std::hash<Key>>
    75→class ThreadSafeLRUCache final
    76→{
    77→public:
    78→    explicit ThreadSafeLRUCache(std::size_t capacity)
    79→        : capacity_{ capacity }
    80→    {
    81→        if (capacity_ == 0) {
    82→            throw std::invalid_argument("LRU cache capacity must be > 0");
    83→        }
    84→    }
    85→
    86→    // Retrieve a value, or std::nullopt if the key isn’t present.
    87→    std::optional<Value> get(const Key& key)
    88→    {
    89→        std::unique_lock lock{ mutex_ };
    90→        auto it = index_.find(key);
    91→        if (it == index_.end()) return std::nullopt;
    92→
    93→        // Move the accessed item to the front of the list to mark it most-recently-used.
    94→        lru_.splice(lru_.begin(), lru_, it->second);
    95→        return it->second->second;
    96→    }
    97→
    98→    // Insert or update.
    99→    void put(Key key, Value value)
   100→    {
   101→        std::unique_lock lock{ mutex_ };
   102→
   103→        auto it = index_.find(key);
   104→        if (it != index_.end()) {
   105→            // Update existing entry and move to front.
   106→            it->second->second = std::move(value);
   107→            lru_.splice(lru_.begin(), lru_, it->second);
   108→            return;
   109→        }
   110→
   111→        // Evict if capacity exceeded.
   112→        if (lru_.size() >= capacity_) {
   113→            const auto& lru_key = lru_.back().first;
   114→            index_.erase(lru_key);
   115→            lru_.pop_back();
   116→        }
   117→
   118→        // Insert new entry at front.
   119→        lru_.emplace_front(std::move(key), std::move(value));
   120→        index_[lru_.front().first] = lru_.begin();
   121→    }
   122→
   123→    std::size_t size() const noexcept
   124→    {
   125→        std::shared_lock lock{ mutex_ };
   126→        return lru_.size();
   127→    }
   128→
   129→private:
   130→    using List        = std::list<std::pair<Key, Value>>;
   131→    using ListIt      = typename List::iterator;
   132→    using Map         = std::unordered_map<Key, ListIt, Hash>;
   133→
   134→    std::size_t capacity_;
   135→    mutable std::shared_mutex mutex_;
   136→    List lru_;   // Front = MRU, Back = LRU
   137→    Map  index_;
   138→};
