   140→// -----------------------------------------------------------------------------
   141→// Snippet generator
   142→// -----------------------------------------------------------------------------
   143→
   144→class SnippetGenerator
   145→{
   146→public:
   147→    struct Options
   148→    {
   149→        std::size_t max_snippet_length   = 220;     // in bytes, not UTF-8 code points
   150→        std::size_t max_highlights       = 3;       // max <mark> blocks
   151→        std::string highlight_start_tag  = "<mark>";
   152→        std::string highlight_end_tag    = "</mark>";
   153→        std::string ellipsis             = "…";
   154→    };
   155→
   156→    SnippetGenerator() = default;
   157→
   158→    // Generate a highlighted snippet.  `body_html` is expected to already have
   159→    // HTML tags stripped and entities decoded (for brevity not included here).
   160→    std::string generate(std::string_view body_html,
   161→                         const std::vector<std::string>& terms,
   162→                         const Options& opts = {}) const
   163→    {
   164→        if (terms.empty()) {
   165→            return summarise(body_html, opts.max_snippet_length, opts.ellipsis);
   166→        }
   167→
   168→        // Lower-cased copies for case-insensitive search.
   169→        std::vector<std::string> lower_terms;
   170→        lower_terms.reserve(terms.size());
   171→        for (auto&& t : terms) {
   172→            auto trimmed = trim_ascii(t);
   173→            if (!trimmed.empty()) {
   174→                lower_terms.push_back(ascii_to_lower(trimmed));
   175→            }
   176→        }
   177→
   178→        std::string lower_body = ascii_to_lower(body_html);
   179→        std::size_t first_hit = std::string::npos;
   180→
   181→        // Identify first occurrence of any term.
   182→        for (const auto& needle : lower_terms) {
   183→            auto pos = lower_body.find(needle);
   184→            if (pos != std::string::npos) {
   185→                first_hit = std::min(first_hit, pos);
   186→            }
   187→        }
   188→
   189→        Options effective_opts = opts;
   190→
   191→        // If no match found, return fallback summary.
   192→        if (first_hit == std::string::npos) {
   193→            return summarise(body_html, effective_opts.max_snippet_length, effective_opts.ellipsis);
   194→        }
   195→
   196→        // Determine snippet window.
   197→        const std::size_t half_window =
   198→            effective_opts.max_snippet_length / 2u > 10 ? effective_opts.max_snippet_length / 2u : 10u;
   199→
   200→        std::size_t snippet_start = (first_hit > half_window) ? first_hit - half_window : 0;
   201→        std::size_t snippet_end   = std::min<std::size_t>(body_html.size(), snippet_start + effective_opts.max_snippet_length);
   202→
   203→        std::string snippet = std::string(body_html.substr(snippet_start, snippet_end - snippet_start));
   204→
   205→        // Highlight occurrences up to max_highlights.
   206→        std::size_t highlights = 0;
   207→        for (const auto& term_raw : lower_terms) {
   208→            std::string term = term_raw;  // copy
   209→            std::size_t pos = ascii_to_lower(snippet).find(term);
   210→            while (pos != std::string::npos && highlights < effective_opts.max_highlights) {
   211→                snippet.insert(pos + term.size(), effective_opts.highlight_end_tag);
   212→                snippet.insert(pos, effective_opts.highlight_start_tag);
   213→                highlights++;
   214→                pos = ascii_to_lower(snippet).find(term, pos + term.size() +
   215→                                                   effective_opts.highlight_start_tag.size() +
   216→                                                   effective_opts.highlight_end_tag.size());
   217→            }
   218→            if (highlights >= effective_opts.max_highlights) break;
   219→        }
   220→
   221→        // Add ellipsis if not at boundaries.
   222→        if (snippet_start > 0) {
   223→            snippet.insert(0, effective_opts.ellipsis);
   224→        }
   225→        if (snippet_end < body_html.size()) {
   226→            snippet.append(effective_opts.ellipsis);
   227→        }
   228→        return snippet;
   229→    }
   230→
   231→private:
   232→    // Return a simple leading summary, respecting byte length.
   233→    static std::string summarise(std::string_view body, std::size_t max_len, std::string_view ellipsis)
   234→    {
   235→        if (body.size() <= max_len) return std::string(body);
   236→        return std::string(body.substr(0, max_len)) + std::string(ellipsis);
   237→    }
   238→};
