   240→// -----------------------------------------------------------------------------
   241→// Cached snippet service (public façade)
   242→// -----------------------------------------------------------------------------
   243→
   244→class CachedSnippetService
   245→{
   246→public:
   247→    using ArticleId = std::uint64_t;
   248→
   249→    explicit CachedSnippetService(std::size_t cache_capacity = 4096)
   250→        : cache_{ cache_capacity }
   251→    {}
   252→
   253→    // High-level API for controllers / services.
   254→    //
   255→    // Parameters:
   256→    //   article_id   – database primary key for the article
   257→    //   body_html    – HTML-stripped article text in UTF-8
   258→    //   query_terms  – individual search terms (already tokenised)
   259→    //
   260→    // The snippet is returned from cache if available; otherwise generated and
   261→    // stored.  Thread-safe for concurrent callers.
   262→    std::string get_snippet(ArticleId                      article_id,
   263→                            std::string_view               body_html,
   264→                            const std::vector<std::string>& query_terms)
   265→    {
   266→        const Key key{ article_id, compute_query_hash(query_terms) };
   267→
   268→        if (auto cached = cache_.get(key); cached.has_value()) {
   269→            return *cached;
   270→        }
   271→
   272→        // Miss: generate.
   273→        std::string snippet = generator_.generate(body_html, query_terms);
   274→
   275→        cache_.put(key, snippet);
   276→        return snippet;
   277→    }
   278→
   279→private:
   280→    // Internal key combining article ID and query hash
   281→    struct Key {
   282→        ArticleId   article_id;
   283→        std::size_t query_hash;
   284→
   285→        bool operator==(const Key& other) const noexcept
   286→        {
   287→            return article_id == other.article_id &&
   288→                   query_hash  == other.query_hash;
   289→        }
   290→    };
   291→
   292→    struct KeyHasher {
   293→        std::size_t operator()(const Key& k) const noexcept
   294→        {
   295→            std::size_t h1 = std::hash<ArticleId>{}(k.article_id);
   296→            std::size_t h2 = std::hash<std::size_t>{}(k.query_hash);
   297→            // Combine (boost::hash_combine recipe)
   298→            return h1 ^ (h2 + 0x9e3779b9 + (h1 << 6) + (h1 >> 2));
   299→        }
   300→    };
   301→
   302→    static std::size_t compute_query_hash(const std::vector<std::string>& terms)
   303→    {
   304→        // Order-insensitively combine hashes of individual terms.
   305→        std::size_t result = 0;
   306→        for (const auto& term : terms) {
   307→            std::size_t h = std::hash<std::string>{}(ascii_to_lower(trim_ascii(term)));
   308→            result ^= h + 0x9e3779b97f4a7c15ULL + (result << 12) + (result >> 4);
   309→        }
   310→        return result;
   311→    }
   312→
   313→    SnippetGenerator                                            generator_;
   314→    ThreadSafeLRUCache<Key, std::string, KeyHasher>             cache_;
   315→};
