   140→    // 1. Initiate Reset Request --------------------------------------------------
   141→    //    Throws RateLimitExceeded if the email has exhausted its quota.
   142→    void requestPasswordReset(std::string_view email)
   143→    {
   144→        validateEmail(email);
   145→
   146→        auto now = std::chrono::system_clock::now();
   147→
   148→        {
   149→            std::scoped_lock lk{m_rateMutex};
