   151→            pruneRateLog(now);
   152→            auto& info = m_rateLog[email];
   153→            if (info.count >= m_cfg.maxTokensPerHour)
   154→                throw RateLimitExceeded{"Too many password-reset requests."};
   155→
   156→            if (now - info.lastRequest < m_cfg.cooldownPerEmail)
   157→                throw RateLimitExceeded{"Password-reset requests are cooling down."};
   158→
   159→            ++info.count;
   160→            info.lastRequest = now;
   161→        }
   162→
   163→        // Generate a secure, unique token.
   164→        const auto token = generateToken();
   165→
   166→        // Persist token with its expiry.
   167→        m_tokenRepo.upsertToken(token, {
   168→            std::string{email},
   169→            now + m_cfg.tokenLifetime
   170→        });
