   172→        // Build reset URL (assumes host rendered on frontend).
   173→        std::ostringstream url;
   174→        url << m_cfg.frontendResetPath << token;
   175→
   176→        // Send e-mail through dispatcher (async).
   177→        m_emailDispatcher.enqueueResetEmail(email, url.str());
   178→    }
   179→
   180→    // 2. Reset Password ----------------------------------------------------------
   181→    //    Validates token, updates password hash, and consumes token.
   182→    void resetPassword(std::string_view token, std::string_view newPasswordHash)
   183→    {
   184→        auto now = std::chrono::system_clock::now();
   185→
   186→        auto record = m_tokenRepo.findToken(token);
   187→        if (!record)
   188→            throw TokenInvalid{"Password-reset token invalid."};
