   221→    // Generates a cryptographically secure, 128-bit token encoded in base62.
   222→    static std::string generateToken()
   223→    {
   224→        constexpr char charset[] =
   225→            "0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ";
   226→        constexpr std::size_t charsetSize = sizeof(charset) - 1;
   227→        constexpr std::size_t bytesNeeded = 16; // 128-bit
   228→        constexpr std::size_t outputLen   = (bytesNeeded * 8 + 5) / 6; // ceil
   229→
   230→        std::array<std::uint8_t, bytesNeeded> randomBytes{};
   231→
   232→        {
   233→            static thread_local std::random_device rd;
   234→            static thread_local std::mt19937_64 rng{rd()};
