   236→            for (auto& b : randomBytes) b = static_cast<std::uint8_t>(dist(rng));
   237→        }
   238→
   239→        // Convert to base62
   240→        std::string token;
   241→        token.reserve(outputLen);
   242→
   243→        std::uint64_t accumulator = 0;
   244→        int bits = 0;
   245→        for (std::uint8_t byte : randomBytes)
   246→        {
   247→            accumulator = (accumulator << 8) | byte;
   248→            bits += 8;
   249→            while (bits >= 6)
   250→            {
   251→                bits -= 6;
   252→                token.push_back(charset[(accumulator >> bits) & 0x3F]);
   253→            }
   254→        }
   255→        if (bits > 0)
