   116→/**
   117→ * Thread-safe, process-wide singleton that collects raw page-view events
   118→ * and flushes the aggregated counters to the persistence layer.
   119→ *
   120→ * Usage:
   121→ *     AnalyticsAggregator::instance().recordView(tenantId, articleId, userId);
   122→ */
   123→class AnalyticsAggregator
   124→{
   125→public:
   126→    // Non-copyable / Non-movable
   127→    AnalyticsAggregator(const AnalyticsAggregator&)            = delete;
   128→    AnalyticsAggregator& operator=(const AnalyticsAggregator&) = delete;
   129→    AnalyticsAggregator(AnalyticsAggregator&&)                 = delete;
   130→    AnalyticsAggregator& operator=(AnalyticsAggregator&&)      = delete;
   131→
   132→    static AnalyticsAggregator& instance()
   133→    {
   134→        static AnalyticsAggregator inst;
   135→        return inst;
   136→    }
   137→
   138→    ~AnalyticsAggregator()
   139→    {
   140→        shutdown();
   141→    }
   142→
   143→    /**
   144→     * Records a page-view event. Extremely hot path; optimized for minimal
   145→     * contention via per-bucket sharding and atomic counters.
   146→     */
   147→    void recordView(std::int64_t tenantId, std::int64_t articleId, std::int64_t /*userId*/)
   148→    {
   149→        const Key key{tenantId, articleId};
   150→        auto& bucket = m_buckets[key % m_buckets.size()];
   151→
   152→        {
   153→            std::unique_lock lk(bucket.mutex);
   154→            ++bucket.map[key];
   155→        }
   156→
   157→        // Fast path: only wake the flusher when certain thresholds are met.
   158→        const auto current = ++m_eventCounter;
   159→        if (current >= m_flushThreshold)
   160→        {
   161→            std::lock_guard lg(m_flushMutex);
   162→            m_shouldFlush = true;
   163→            m_cvFlush.notify_one();
   164→        }
   165→    }
   166→
   167→    /**
   168→     * Graceful shutdown – ensures all counters make it to persistent storage.
   169→     * Safe to call multiple times.
   170→     */
   171→    void shutdown()
   172→    {
   173→        bool expected = false;
   174→        if (!m_shutdown.compare_exchange_strong(expected, true)) return;
   175→
   176→        {
   177→            std::lock_guard lg(m_flushMutex);
   178→            m_shouldFlush = true;
   179→            m_cvFlush.notify_one();
   180→        }
   181→        if (m_flushThread.joinable()) m_flushThread.join();
   182→    }
   183→
   184→private:
   185→    // ───── Types ────────────────────────────────────────────────────────────
   186→    struct Key
   187→    {
   188→        std::int64_t tenantId;
   189→        std::int64_t articleId;
   190→
   191→        std::size_t operator%(std::size_t mod) const noexcept
   192→        {
   193→            // Simple mixing hash for bucket selection.
   194→            std::uint64_t h = static_cast<std::uint64_t>(tenantId) ^ (static_cast<std::uint64_t>(articleId) << 1);
   195→            return static_cast<std::size_t>(h % mod);
   196→        }
   197→
   198→        bool operator==(const Key& other) const noexcept
   199→        {
   200→            return tenantId == other.tenantId && articleId == other.articleId;
   201→        }
   202→    };
   203→
   204→    struct KeyHash
   205→    {
   206→        std::size_t operator()(const Key& k) const noexcept
   207→        {
   208→            return k.tenantId * 31ull ^ k.articleId;
   209→        }
   210→    };
   211→
   212→    using Map  = std::unordered_map<Key, std::uint64_t, KeyHash>;
   213→    using Pair = std::pair<Key, std::uint64_t>;
   214→
   215→    struct Bucket
   216→    {
