   227→    // ───── Flushing Logic ───────────────────────────────────────────────────
   228→    void flushLoop()
   229→    {
   230→        auto nextWake = std::chrono::steady_clock::now() + m_flushInterval;
   231→        std::unique_lock lk(m_flushMutex);
   232→
   233→        while (!m_shutdown.load(std::memory_order_acquire))
   234→        {
   235→            m_cvFlush.wait_until(lk, nextWake, [this] { return m_shouldFlush || m_shutdown.load(); });
