   237→            lk.unlock();
   238→
   239→            try
   240→            {
   241→                flushOnce();
   242→            }
   243→            catch (const std::exception& ex)
   244→            {
   245→                // Log and continue. In production use a proper logger.
   246→                std::cerr << "[AnalyticsAggregator] flush failed: " << ex.what() << '\n';
   247→            }
   248→
   249→            nextWake = std::chrono::steady_clock::now() + m_flushInterval;
   250→            lk.lock();
   251→        }
   252→
   253→        // Final flush on shutdown
   254→        lk.unlock();
   255→        flushOnce();
   256→    }
   257→
   258→    void flushOnce()
   259→    {
   260→        // Move data out of buckets with minimal holding time.
   261→        std::vector<Pair> snapshot;
   262→        snapshot.reserve(m_eventCounter.load());
   263→
   264→        for (auto& bucket : m_buckets)
   265→        {
   266→            std::lock_guard lg(bucket.mutex);
   267→            for (auto& [k, v] : bucket.map)
   268→            {
   269→                snapshot.emplace_back(k, v);
   270→            }
   271→            bucket.map.clear();
   272→        }
   273→
   274→        if (snapshot.empty()) return;
   275→        m_eventCounter = 0;
   276→
   277→        // Aggregate duplicates (rare; only occurs if hash bucket collision across shards).
   278→        std::unordered_map<Key, std::uint64_t, KeyHash> aggregated;
   279→        aggregated.reserve(snapshot.size());
   280→        for (const auto& [k, v] : snapshot) aggregated[k] += v;
