   282→        // Persist to DB
   283→        orm::DbSession session;
   284→        repository::AnalyticsRepository repo(session);
   285→
   286→        session.transactional([&](orm::DbSession& /*tx*/) {
   287→            std::vector<repository::AnalyticsUpdate> batch;
   288→            batch.reserve(aggregated.size());
   289→
   290→            for (const auto& [k, count] : aggregated)
   291→            {
   292→                batch.push_back({k.tenantId, k.articleId, count});
   293→                if (batch.size() >= m_dbBatchSize)
   294→                {
   295→                    repo.bulkIncrement(batch);
   296→                    batch.clear();
   297→                }
   298→            }
   299→            if (!batch.empty()) repo.bulkIncrement(batch);
   300→        });
   301→    }
