   304→    static constexpr std::size_t kShardCount   = 64;
   305→    static constexpr std::uint64_t kDefaultThreshold = 10'000;
   306→
   307→    std::array<Bucket, kShardCount>    m_buckets{};
   308→    std::atomic<std::uint64_t>         m_eventCounter{0};
